macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn solve() {
    let (n, m, min, max) = parse_line!(usize, usize, i64, i64);
    let t = parse_line_to_vec!(i64);
    let low = t.iter().fold(std::i64::MAX, |x, &y| std::cmp::min(x, y));
    let high = t.iter().fold(std::i64::MIN, |x, &y| std::cmp::max(x, y));
    let mut fail = low < min || high > max;
    fail |= (low != min && high != max && n - m < 2) ||
        ((low != min || high != max) && n - m < 1);
    if fail {
        println!("Incorrect")
    }else{
        println!("Correct")
    }
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
